useEffect(() => {
  const load = async () => {
    setLoading(true);
    try {
      const res = await fetch(`/api/users?key=${API_KEY}`);
      if (!res.ok) throw new Error('Fetch failed');
      setUsers(await res.json());
    } catch (error) {
      setError(error.message);
    } finally {
      setLoading(false);
    }
  };
  load();
}, []);
